import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Package, ShoppingBag, TrendingUp, Star, ArrowRight, Clock } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { useTheme } from '../../context/ThemeContext';
import { formatPrice, getTimeAgo } from '../../lib/utils';
import { ORDER_STATUSES } from '../../lib/constants';
import Spinner from '../../components/ui/Spinner';

export default function DashboardPage() {
  const { shop } = useAuth();
  const { isDark } = useTheme();
  const [stats, setStats] = useState({ orders: 0, revenue: 0, pending: 0, products: 0 });
  const [recentOrders, setRecentOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { if (shop) { fetchStats(); fetchRecentOrders(); } }, [shop]);

  async function fetchStats() {
    const [ordersRes, productsRes] = await Promise.all([
      supabase.from('orders').select('*').eq('shop_id', shop.id),
      supabase.from('products').select('id', { count: 'exact' }).eq('shop_id', shop.id),
    ]);
    const orders = ordersRes.data || [];
    const revenue = orders.filter(o => o.status === 'delivered').reduce((s, o) => s + Number(o.total_amount), 0);
    const pending = orders.filter(o => o.status === 'pending').length;
    setStats({ orders: orders.length, revenue, pending, products: productsRes.count || 0 });
  }

  async function fetchRecentOrders() {
    const { data } = await supabase.from('orders').select('*, profiles!orders_customer_id_fkey(full_name)').eq('shop_id', shop.id).order('created_at', { ascending: false }).limit(5);
    setRecentOrders(data || []);
    setLoading(false);
  }

  const c = (light, dark) => isDark ? dark : light;

  if (!shop) return <div style={{ padding: '24px', textAlign: 'center', color: c('#64748B', '#94A3B8') }}>Setting up your shop...</div>;
  if (loading) return <Spinner />;

  const statCards = [
    { icon: ShoppingBag, label: 'Total Orders', value: stats.orders, bg: 'linear-gradient(135deg, #6C63FF, #4F46B8)' },
    { icon: TrendingUp, label: 'Revenue', value: formatPrice(stats.revenue), bg: 'linear-gradient(135deg, #10B981, #059669)' },
    { icon: Clock, label: 'Pending', value: stats.pending, bg: 'linear-gradient(135deg, #F59E0B, #D97706)' },
    { icon: Package, label: 'Products', value: stats.products, bg: 'linear-gradient(135deg, #8B5CF6, #6D28D9)' },
  ];

  return (
    <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '24px 16px 100px' }}>
      <div style={{ marginBottom: '32px' }}>
        <h1 style={{ fontSize: '28px', fontWeight: 800, color: c('#0F172A', 'white'), margin: '0 0 4px' }}>Dashboard 📊</h1>
        <p style={{ color: '#64748B', fontSize: '14px', margin: 0 }}>Welcome back, {shop.name}!</p>
      </div>

      {/* Stats Grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px', marginBottom: '32px' }}>
        {statCards.map((stat, i) => (
          <div key={i} style={{ background: stat.bg, padding: '24px', borderRadius: '20px', color: 'white', boxShadow: '0 8px 24px rgba(0,0,0,0.1)' }}>
            <stat.icon size={24} style={{ opacity: 0.8, marginBottom: '12px' }} />
            <p style={{ fontSize: '28px', fontWeight: 800, margin: '0 0 4px' }}>{stat.value}</p>
            <p style={{ fontSize: '14px', opacity: 0.8, margin: 0, fontWeight: 500 }}>{stat.label}</p>
          </div>
        ))}
      </div>

      {/* Shop Rating */}
      <div style={{ padding: '24px', borderRadius: '20px', background: c('white', 'rgba(255,255,255,0.03)'), border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.08)')}`, marginBottom: '32px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          <div style={{ width: '48px', height: '48px', borderRadius: '12px', background: c('#FEF3C7', 'rgba(245,158,11,0.15)'), display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Star size={24} color="#F59E0B" fill="#F59E0B" />
          </div>
          <div>
            <p style={{ color: '#64748B', fontSize: '13px', margin: '0 0 2px', fontWeight: 500 }}>Shop Rating</p>
            <p style={{ fontSize: '24px', fontWeight: 800, color: c('#0F172A', 'white'), margin: 0 }}>{shop.rating > 0 ? Number(shop.rating).toFixed(1) : 'No ratings yet'}</p>
          </div>
        </div>
        <p style={{ color: '#64748B', fontSize: '14px', margin: 0 }}>{shop.total_ratings || 0} reviews</p>
      </div>

      {/* Recent Orders */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
        <h2 style={{ fontSize: '18px', fontWeight: 800, color: c('#0F172A', 'white'), margin: 0 }}>Recent Orders</h2>
        <Link to="/dashboard/orders" style={{ color: '#6C63FF', fontSize: '14px', fontWeight: 700, textDecoration: 'none', display: 'flex', alignItems: 'center', gap: '4px' }}>
          View all <ArrowRight size={16} />
        </Link>
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
        {recentOrders.length === 0 ? (
          <div style={{ padding: '32px', textAlign: 'center', background: c('white', 'rgba(255,255,255,0.03)'), borderRadius: '16px', border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.08)')}` }}>
            <p style={{ color: '#64748B', fontSize: '14px', margin: 0 }}>No orders yet. Share your shop to get started! 🚀</p>
          </div>
        ) : recentOrders.map(order => (
          <div key={order.id} style={{ padding: '20px', borderRadius: '16px', background: c('white', 'rgba(255,255,255,0.03)'), border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.08)')}`, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div>
              <p style={{ fontSize: '15px', fontWeight: 700, color: c('#0F172A', 'white'), margin: '0 0 4px' }}>{order.order_number}</p>
              <p style={{ color: '#64748B', fontSize: '13px', margin: 0 }}>{order.profiles?.full_name} · {getTimeAgo(order.created_at)}</p>
            </div>
            <div style={{ textAlign: 'right' }}>
              <p style={{ fontSize: '15px', fontWeight: 800, color: '#6C63FF', margin: '0 0 6px' }}>{formatPrice(order.total_amount)}</p>
              <span style={{ display: 'inline-flex', alignItems: 'center', gap: '4px', padding: '4px 10px', borderRadius: '100px', fontSize: '12px', fontWeight: 600, background: ORDER_STATUSES[order.status]?.color?.includes('success') ? 'rgba(16,185,129,0.1)' : ORDER_STATUSES[order.status]?.color?.includes('warning') ? 'rgba(245,158,11,0.1)' : 'rgba(108,99,255,0.1)', color: ORDER_STATUSES[order.status]?.color?.includes('success') ? '#10B981' : ORDER_STATUSES[order.status]?.color?.includes('warning') ? '#F59E0B' : '#6C63FF' }}>
                {ORDER_STATUSES[order.status]?.icon} {ORDER_STATUSES[order.status]?.label}
              </span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Plus, Edit3, Trash2, Package, Search, ToggleLeft, ToggleRight, Upload } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { useTheme } from '../../context/ThemeContext';
import { formatPrice } from '../../lib/utils';
import { CATEGORIES, UNITS } from '../../lib/constants';
import Spinner from '../../components/ui/Spinner';
import toast from 'react-hot-toast';

const emptyProduct = { name: '', description: '', price: '', category_id: '', unit: 'piece', in_stock: true, image_url: '' };

export default function ProductsPage() {
  const { shop } = useAuth();
  const { isDark } = useTheme();
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [modal, setModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [form, setForm] = useState({ ...emptyProduct });
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);

  const c = (light, dark) => isDark ? dark : light;

  useEffect(() => { if (shop) fetchProducts(); }, [shop]);

  async function fetchProducts() {
    setLoading(true);
    const { data } = await supabase.from('products').select('*').eq('shop_id', shop.id).order('created_at', { ascending: false });
    setProducts(data || []);
    setLoading(false);
  }

  function openAdd() { setForm({ ...emptyProduct }); setEditingProduct(null); setModal(true); }
  function openEdit(product) { setForm({ ...product }); setEditingProduct(product); setModal(true); }

  async function handleSave() {
    if (!form.name || !form.price) return toast.error('Name and price required');
    setSaving(true);
    try {
      if (editingProduct) {
        const { error } = await supabase.from('products').update({
          name: form.name, description: form.description, price: Number(form.price),
          category_id: form.category_id || null, unit: form.unit, in_stock: form.in_stock, image_url: form.image_url,
        }).eq('id', editingProduct.id);
        if (error) throw error;
        toast.success('Product updated! ✅');
      } else {
        const { error } = await supabase.from('products').insert({
          shop_id: shop.id, name: form.name, description: form.description, price: Number(form.price),
          category_id: form.category_id || null, unit: form.unit, in_stock: form.in_stock, image_url: form.image_url,
        });
        if (error) throw error;
        toast.success('Product added! 🎉');
      }
      setModal(false);
      fetchProducts();
    } catch (err) { toast.error(err.message); } finally { setSaving(false); }
  }

  async function handleDelete(id) {
    if (!window.confirm('Delete this product?')) return;
    await supabase.from('products').delete().eq('id', id);
    toast.success('Product deleted');
    fetchProducts();
  }

  async function toggleStock(product) {
    await supabase.from('products').update({ in_stock: !product.in_stock }).eq('id', product.id);
    setProducts(prev => prev.map(p => p.id === product.id ? { ...p, in_stock: !p.in_stock } : p));
    toast.success(product.in_stock ? 'Marked out of stock' : 'Marked in stock');
  }

  async function uploadProductImage(file) {
    setUploading(true);
    try {
      const ext = file.name.split('.').pop();
      const path = `products/${shop.id}/${Date.now()}.${ext}`;
      const { error } = await supabase.storage.from('shop-assets').upload(path, file);
      if (error) throw error;
      const { data } = supabase.storage.from('shop-assets').getPublicUrl(path);
      setForm(prev => ({ ...prev, image_url: data.publicUrl }));
      toast.success('Image uploaded!');
    } catch (err) { toast.error(err.message); } finally { setUploading(false); }
  }

  const filtered = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));

  const inputStyle = { width: '100%', padding: '12px 16px', borderRadius: '12px', border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.1)')}`, background: c('white', 'rgba(255,255,255,0.05)'), color: c('#0F172A', 'white'), fontSize: '14px', outline: 'none', boxSizing: 'border-box' };
  const labelStyle = { display: 'block', fontSize: '13px', fontWeight: 600, color: c('#334155', '#CBD5E1'), marginBottom: '6px' };

  if (loading) return <Spinner />;

  return (
    <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '24px 16px 100px' }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '24px' }}>
        <div>
          <h1 style={{ fontSize: '28px', fontWeight: 800, color: c('#0F172A', 'white'), margin: '0 0 4px' }}>Products 📦</h1>
          <p style={{ color: '#64748B', fontSize: '14px', margin: 0 }}>{products.length} products</p>
        </div>
        <button onClick={openAdd} style={{ padding: '10px 16px', borderRadius: '12px', background: 'linear-gradient(135deg, #6C63FF, #5B52E5)', color: 'white', fontWeight: 700, fontSize: '14px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', boxShadow: '0 4px 12px rgba(108,99,255,0.3)' }}>
          <Plus size={18} /> Add Product
        </button>
      </div>

      <div style={{ position: 'relative', marginBottom: '24px' }}>
        <Search size={18} style={{ position: 'absolute', left: '16px', top: '50%', transform: 'translateY(-50%)', color: '#94A3B8' }} />
        <input type="text" placeholder="Search products..." value={search} onChange={e => setSearch(e.target.value)}
          style={{ width: '100%', padding: '14px 16px 14px 44px', borderRadius: '14px', border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.08)')}`, background: c('white', 'rgba(255,255,255,0.03)'), color: c('#0F172A', 'white'), fontSize: '14px', outline: 'none', boxSizing: 'border-box' }} />
      </div>

      {filtered.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '60px 20px', background: c('white', 'rgba(255,255,255,0.03)'), borderRadius: '20px', border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.08)')}` }}>
          <Package size={48} color="#6C63FF" style={{ margin: '0 auto 16px', opacity: 0.8 }} />
          <h3 style={{ fontSize: '18px', fontWeight: 700, color: c('#1E293B', 'white'), margin: '0 0 8px' }}>No products</h3>
          <p style={{ color: '#64748B', fontSize: '14px', margin: '0 0 20px' }}>Add your first product to start selling!</p>
          <button onClick={openAdd} style={{ padding: '10px 20px', borderRadius: '12px', background: '#6C63FF', color: 'white', fontWeight: 700, fontSize: '14px', border: 'none', cursor: 'pointer' }}>
            + Add Product
          </button>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px' }}>
          {filtered.map((product) => (
            <div key={product.id} style={{ borderRadius: '16px', overflow: 'hidden', border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.08)')}`, background: c('white', 'rgba(255,255,255,0.03)') }}>
              <div style={{ height: '160px', position: 'relative', background: c('#F1F5F9', '#1E293B') }}>
                {product.image_url ? <img src={product.image_url} alt={product.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '40px' }}>📦</div>}
                {!product.in_stock && <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><span style={{ color: 'white', fontWeight: 800, fontSize: '14px' }}>Out of Stock</span></div>}
              </div>

              <div style={{ padding: '16px' }}>
                <h3 style={{ fontSize: '15px', fontWeight: 700, color: c('#0F172A', 'white'), margin: '0 0 8px' }}>{product.name}</h3>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px' }}>
                  <span style={{ fontWeight: 800, color: '#6C63FF', fontSize: '15px' }}>{formatPrice(product.price)}<span style={{ color: '#94A3B8', fontSize: '12px', fontWeight: 500 }}>/{product.unit}</span></span>
                  <span style={{ padding: '4px 8px', borderRadius: '100px', fontSize: '11px', fontWeight: 700, background: product.in_stock ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)', color: product.in_stock ? '#10B981' : '#EF4444' }}>
                    {product.in_stock ? '● In Stock' : '● Out'}
                  </span>
                </div>

                <div style={{ display: 'flex', gap: '8px', borderTop: `1px solid ${c('#F1F5F9', 'rgba(255,255,255,0.05)')}`, paddingTop: '16px' }}>
                  <button onClick={() => openEdit(product)} style={{ display: 'flex', alignItems: 'center', gap: '6px', padding: '8px 12px', borderRadius: '10px', background: c('#F1F5F9', 'rgba(255,255,255,0.06)'), color: c('#334155', '#CBD5E1'), fontWeight: 600, fontSize: '13px', border: 'none', cursor: 'pointer' }}>
                    <Edit3 size={14} /> Edit
                  </button>
                  <button onClick={() => toggleStock(product)} style={{ padding: '8px', borderRadius: '10px', background: c('#F1F5F9', 'rgba(255,255,255,0.06)'), border: 'none', cursor: 'pointer' }}>
                    {product.in_stock ? <ToggleRight size={18} color="#10B981" /> : <ToggleLeft size={18} color="#94A3B8" />}
                  </button>
                  <button onClick={() => handleDelete(product.id)} style={{ padding: '8px', borderRadius: '10px', background: 'rgba(239,68,68,0.1)', border: 'none', cursor: 'pointer', marginLeft: 'auto' }}>
                    <Trash2 size={16} color="#EF4444" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Add/Edit Modal */}
      {modal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 50, padding: '16px' }} onClick={() => setModal(false)}>
          <div style={{ background: c('white', '#0F172A'), borderRadius: '24px', padding: '32px', maxWidth: '500px', width: '100%', maxHeight: '90vh', overflowY: 'auto', boxShadow: '0 24px 48px rgba(0,0,0,0.3)' }} onClick={e => e.stopPropagation()}>
            <h3 style={{ fontSize: '20px', fontWeight: 800, color: c('#0F172A', 'white'), marginBottom: '24px' }}>{editingProduct ? 'Edit Product' : 'Add Product'}</h3>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
              <div><label style={labelStyle}>Product Name *</label><input type="text" value={form.name} onChange={e => setForm(p => ({ ...p, name: e.target.value }))} placeholder="e.g. Amul Milk 500ml" style={inputStyle} /></div>
              <div><label style={labelStyle}>Description</label><input type="text" value={form.description} onChange={e => setForm(p => ({ ...p, description: e.target.value }))} placeholder="Brief description" style={inputStyle} /></div>
              <div style={{ display: 'flex', gap: '16px' }}>
                <div style={{ flex: 1 }}><label style={labelStyle}>Price (₹) *</label><input type="number" value={form.price} onChange={e => setForm(p => ({ ...p, price: e.target.value }))} placeholder="0" style={inputStyle} /></div>
                <div style={{ flex: 1 }}><label style={labelStyle}>Unit</label>
                  <select value={form.unit} onChange={e => setForm(p => ({ ...p, unit: e.target.value }))} style={{ ...inputStyle, cursor: 'pointer' }}>
                    {UNITS.map(u => <option key={u} value={u}>{u}</option>)}
                  </select>
                </div>
              </div>
              <div><label style={labelStyle}>Category</label>
                <select value={form.category_id} onChange={e => setForm(p => ({ ...p, category_id: e.target.value }))} style={{ ...inputStyle, cursor: 'pointer' }}>
                  <option value="">Select category</option>
                  {CATEGORIES.map(cat => <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>)}
                </select>
              </div>
              <div><label style={labelStyle}>Product Image</label>
                <div style={{ display: 'flex', gap: '16px', alignItems: 'center' }}>
                  <label style={{ display: 'inline-flex', alignItems: 'center', gap: '8px', padding: '10px 16px', borderRadius: '12px', border: `1px dashed ${c('#CBD5E1', '#475569')}`, cursor: 'pointer', background: c('#F8FAFC', 'rgba(255,255,255,0.02)') }}>
                    <Upload size={16} color="#64748B" />
                    <span style={{ fontSize: '13px', color: '#64748B', fontWeight: 600 }}>{uploading ? 'Uploading...' : 'Upload Image'}</span>
                    <input type="file" accept="image/*" style={{ display: 'none' }} onChange={e => e.target.files[0] && uploadProductImage(e.target.files[0])} />
                  </label>
                  {form.image_url && <img src={form.image_url} alt="" style={{ width: '48px', height: '48px', borderRadius: '12px', objectFit: 'cover' }} />}
                </div>
              </div>
              <label style={{ display: 'flex', alignItems: 'center', gap: '12px', cursor: 'pointer', marginTop: '8px' }}>
                <input type="checkbox" checked={form.in_stock} onChange={e => setForm(p => ({ ...p, in_stock: e.target.checked }))} style={{ width: '20px', height: '20px', accentColor: '#6C63FF' }} />
                <span style={{ fontSize: '14px', color: c('#334155', '#CBD5E1'), fontWeight: 600 }}>Item is in stock</span>
              </label>

              <div style={{ display: 'flex', gap: '12px', marginTop: '16px' }}>
                <button onClick={() => setModal(false)} style={{ flex: 1, padding: '14px', borderRadius: '12px', background: c('#F1F5F9', 'rgba(255,255,255,0.05)'), color: c('#475569', '#CBD5E1'), fontWeight: 700, fontSize: '15px', border: 'none', cursor: 'pointer' }}>Cancel</button>
                <button onClick={handleSave} disabled={saving} style={{ flex: 1, padding: '14px', borderRadius: '12px', background: '#6C63FF', color: 'white', fontWeight: 700, fontSize: '15px', border: 'none', cursor: saving ? 'wait' : 'pointer', opacity: saving ? 0.7 : 1, boxShadow: '0 4px 12px rgba(108,99,255,0.3)' }}>{saving ? '⏳ Saving...' : (editingProduct ? 'Save Changes' : 'Add Product')}</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { MapPin, Clock, Upload, Camera } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { useTheme } from '../../context/ThemeContext';
import { AREAS } from '../../lib/constants';
import toast from 'react-hot-toast';

export default function ShopProfilePage() {
  const { shop, updateShop } = useAuth();
  const { isDark } = useTheme();
  const [form, setForm] = useState({
    name: shop?.name || '', description: shop?.description || '', address: shop?.address || '',
    area: shop?.area || '', phone: shop?.phone || '', upi_id: shop?.upi_id || '',
    whatsapp_number: shop?.whatsapp_number || '', open_time: shop?.open_time || '09:00',
    close_time: shop?.close_time || '21:00', is_open: shop?.is_open ?? true,
    latitude: shop?.latitude || '', longitude: shop?.longitude || '',
  });
  const [uploading, setUploading] = useState(false);

  const c = (light, dark) => isDark ? dark : light;
  const inputStyle = { width: '100%', padding: '12px 16px', borderRadius: '12px', border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.1)')}`, background: c('white', 'rgba(255,255,255,0.05)'), color: c('#0F172A', 'white'), fontSize: '14px', outline: 'none', boxSizing: 'border-box' };
  const labelStyle = { display: 'block', fontSize: '13px', fontWeight: 600, color: c('#334155', '#CBD5E1'), marginBottom: '6px' };
  const cardStyle = { padding: '24px', borderRadius: '20px', background: c('white', 'rgba(255,255,255,0.03)'), border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.08)')}`, marginBottom: '24px' };

  function handleChange(field, value) { setForm(prev => ({ ...prev, [field]: value })); }

  async function handleSave() {
    await updateShop(form);
  }

  async function uploadImage(file, type) {
    setUploading(true);
    try {
      const ext = file.name.split('.').pop();
      const path = `shops/${shop.id}/${type}.${ext}`;
      const { error: upErr } = await supabase.storage.from('shop-assets').upload(path, file, { upsert: true });
      if (upErr) throw upErr;
      const { data } = supabase.storage.from('shop-assets').getPublicUrl(path);
      await updateShop({ [`${type}_url`]: data.publicUrl });
      toast.success(`${type === 'logo' ? 'Logo' : 'Cover'} updated!`);
    } catch (err) { toast.error(err.message); } finally { setUploading(false); }
  }

  async function detectShopLocation() {
    try {
      const pos = await new Promise((res, rej) => navigator.geolocation.getCurrentPosition(res, rej, { timeout: 10000 }));
      const { latitude, longitude } = pos.coords;
      handleChange('latitude', latitude);
      handleChange('longitude', longitude);

      try {
        const res = await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${latitude}&lon=${longitude}&format=json&accept-language=en`);
        const data = await res.json();
        const locality = data.address?.suburb || data.address?.neighbourhood || data.address?.city_district || data.address?.county || '';

        if (locality) {
          const match = AREAS.find(a => locality.toLowerCase().includes(a.toLowerCase()) || a.toLowerCase().includes(locality.toLowerCase()));
          handleChange('area', match || locality);
          toast.success(`Detected: ${match || locality} 📍. Save to apply.`);
          return;
        }
      } catch (e) {
        console.error('Reverse geocoding failed', e);
      }

      toast.success('Coordinates detected! Save to apply.');
    } catch { toast.error('Could not detect location'); }
  }

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto', padding: '24px 16px 100px' }}>
      <h1 style={{ fontSize: '28px', fontWeight: 800, color: c('#0F172A', 'white'), marginBottom: '24px' }}>Shop Settings ⚙️</h1>

      {/* Images */}
      <div style={cardStyle}>
        <h2 style={{ fontSize: '16px', fontWeight: 800, color: c('#0F172A', 'white'), marginBottom: '16px' }}>Shop Images</h2>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
          <div>
            <p style={{ ...labelStyle, marginBottom: '8px' }}>Logo</p>
            <label style={{ display: 'block', width: '96px', height: '96px', borderRadius: '16px', border: `2px dashed ${c('#CBD5E1', '#475569')}`, background: c('#F8FAFC', 'rgba(255,255,255,0.02)'), cursor: 'pointer', overflow: 'hidden' }}>
              {shop?.logo_url ? <img src={shop.logo_url} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> :
                <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Camera size={24} color="#94A3B8" /></div>}
              <input type="file" accept="image/*" style={{ display: 'none' }} onChange={e => e.target.files[0] && uploadImage(e.target.files[0], 'logo')} />
            </label>
          </div>
          <div>
            <p style={{ ...labelStyle, marginBottom: '8px' }}>Cover</p>
            <label style={{ display: 'block', height: '96px', borderRadius: '16px', border: `2px dashed ${c('#CBD5E1', '#475569')}`, background: c('#F8FAFC', 'rgba(255,255,255,0.02)'), cursor: 'pointer', overflow: 'hidden' }}>
              {shop?.cover_url ? <img src={shop.cover_url} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> :
                <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Upload size={24} color="#94A3B8" /></div>}
              <input type="file" accept="image/*" style={{ display: 'none' }} onChange={e => e.target.files[0] && uploadImage(e.target.files[0], 'cover')} />
            </label>
          </div>
        </div>
      </div>

      {/* Details */}
      <div style={cardStyle}>
        <h2 style={{ fontSize: '16px', fontWeight: 800, color: c('#0F172A', 'white'), marginBottom: '16px' }}>Shop Details</h2>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
          {[{ label: 'Shop Name', field: 'name', type: 'text', placeholder: 'Your shop name' },
            { label: 'Description', field: 'description', type: 'textarea', placeholder: 'Tell customers about your shop...' },
            { label: 'Address', field: 'address', type: 'text', placeholder: 'Full address' },
            { label: 'Phone', field: 'phone', type: 'tel', placeholder: '10-digit phone' },
            { label: 'UPI ID', field: 'upi_id', type: 'text', placeholder: 'yourname@upi' },
            { label: 'WhatsApp Number', field: 'whatsapp_number', type: 'tel', placeholder: 'WhatsApp number' },
          ].map(({ label, field, type, placeholder }) => (
            <div key={field}>
              <label style={labelStyle}>{label}</label>
              {type === 'textarea' ? (
                <textarea value={form[field]} onChange={e => handleChange(field, e.target.value)} rows={2} placeholder={placeholder} style={{ ...inputStyle, resize: 'none' }} />
              ) : (
                <input type={type} value={form[field]} onChange={e => handleChange(field, e.target.value)} placeholder={placeholder} style={inputStyle} />
              )}
            </div>
          ))}

          <div>
            <label style={labelStyle}>Area</label>
            <input type="text" value={form.area} onChange={e => handleChange('area', e.target.value)}
              list="shop-area-suggestions" placeholder="Type your area..." style={inputStyle} />
            <datalist id="shop-area-suggestions">
              {AREAS.map(a => <option key={a} value={a} />)}
            </datalist>
          </div>
        </div>
      </div>

      {/* Location */}
      <div style={cardStyle}>
        <h2 style={{ fontSize: '16px', fontWeight: 800, color: c('#0F172A', 'white'), marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <MapPin size={18} color="#6C63FF" /> Map Location
        </h2>
        <p style={{ color: '#64748B', fontSize: '14px', marginBottom: '16px' }}>Set your shop location so customers can find you on the map.</p>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', marginBottom: '16px' }}>
          <input type="number" step="any" value={form.latitude} onChange={e => handleChange('latitude', e.target.value)} placeholder="Latitude" style={inputStyle} />
          <input type="number" step="any" value={form.longitude} onChange={e => handleChange('longitude', e.target.value)} placeholder="Longitude" style={inputStyle} />
        </div>
        <button onClick={detectShopLocation} style={{ padding: '10px 16px', borderRadius: '12px', border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.1)')}`, background: c('white', 'rgba(255,255,255,0.05)'), color: c('#0F172A', 'white'), fontSize: '13px', fontWeight: 600, cursor: 'pointer' }}>
          📍 Auto Detect My Location
        </button>
      </div>

      {/* Hours & Status */}
      <div style={cardStyle}>
        <h2 style={{ fontSize: '16px', fontWeight: 800, color: c('#0F172A', 'white'), marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <Clock size={18} color="#6C63FF" /> Operating Hours
        </h2>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', marginBottom: '20px' }}>
          <div><label style={{ ...labelStyle, fontSize: '12px', color: '#64748B' }}>Opens at</label>
            <input type="time" value={form.open_time} onChange={e => handleChange('open_time', e.target.value)} style={inputStyle} /></div>
          <div><label style={{ ...labelStyle, fontSize: '12px', color: '#64748B' }}>Closes at</label>
            <input type="time" value={form.close_time} onChange={e => handleChange('close_time', e.target.value)} style={inputStyle} /></div>
        </div>
        <label style={{ display: 'flex', alignItems: 'center', gap: '12px', cursor: 'pointer' }}>
          <input type="checkbox" checked={form.is_open} onChange={e => handleChange('is_open', e.target.checked)} style={{ width: '20px', height: '20px', accentColor: '#6C63FF' }} />
          <span style={{ fontSize: '14px', fontWeight: 600, color: c('#334155', '#CBD5E1') }}>Shop is currently open</span>
        </label>
      </div>

      <button onClick={handleSave} style={{ width: '100%', padding: '16px', borderRadius: '16px', background: '#6C63FF', color: 'white', fontWeight: 800, fontSize: '16px', border: 'none', cursor: 'pointer', boxShadow: '0 8px 24px rgba(108,99,255,0.3)' }}>
        Save Changes ✅
      </button>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Check, X, Truck, ChevronDown, ChevronUp, Filter, ShoppingBag } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { useTheme } from '../../context/ThemeContext';
import { formatPrice, getTimeAgo } from '../../lib/utils';
import { ORDER_STATUSES } from '../../lib/constants';
import Spinner from '../../components/ui/Spinner';
import toast from 'react-hot-toast';

export default function ShopkeeperOrdersPage() {
  const { shop } = useAuth();
  const { isDark } = useTheme();
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [expandedOrder, setExpandedOrder] = useState(null);

  const c = (light, dark) => isDark ? dark : light;

  useEffect(() => { if (shop) { fetchOrders(); subscribeOrders(); } }, [shop]);

  async function fetchOrders() {
    setLoading(true);
    const { data } = await supabase.from('orders')
      .select('*, profiles!orders_customer_id_fkey(full_name, phone, area), order_items(*)')
      .eq('shop_id', shop.id).order('created_at', { ascending: false });
    setOrders(data || []);
    setLoading(false);
  }

  function subscribeOrders() {
    const channel = supabase.channel('shop-orders').on('postgres_changes',
      { event: 'INSERT', schema: 'public', table: 'orders', filter: `shop_id=eq.${shop.id}` },
      () => { fetchOrders(); toast.success('New order received! 🎉'); new Audio('data:audio/wav;base64,UklGRl9vT19XQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YQ==').play().catch(() => {}); }
    ).subscribe();
    return () => supabase.removeChannel(channel);
  }

  async function updateOrderStatus(orderId, status, customerId) {
    await supabase.from('orders').update({ status, updated_at: new Date().toISOString() }).eq('id', orderId);
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status } : o));
    await supabase.from('notifications').insert({
      user_id: customerId, title: `Order ${ORDER_STATUSES[status]?.label}`,
      message: `Your order status has been updated to ${status}`, type: 'order_update',
    });
    toast.success(`Order ${status}`);
  }

  const filtered = filter === 'all' ? orders : orders.filter(o => o.status === filter);
  const filterTabs = ['all', 'pending', 'accepted', 'preparing', 'delivered', 'rejected'];

  if (loading) return <Spinner />;

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto', padding: '24px 16px 100px' }}>
      <h1 style={{ fontSize: '28px', fontWeight: 800, color: c('#0F172A', 'white'), marginBottom: '24px' }}>Orders 📋</h1>

      {/* Filter Tabs */}
      <div style={{ display: 'flex', gap: '8px', marginBottom: '24px', overflowX: 'auto', paddingBottom: '8px', scrollbarWidth: 'none' }}>
        {filterTabs.map(tab => (
          <button key={tab} onClick={() => setFilter(tab)}
            style={{
              padding: '8px 16px', borderRadius: '12px', fontSize: '14px', fontWeight: 600, whiteSpace: 'nowrap', cursor: 'pointer', transition: 'all 0.2s', textTransform: 'capitalize', border: 'none',
              background: filter === tab ? '#6C63FF' : c('#F1F5F9', 'rgba(255,255,255,0.05)'),
              color: filter === tab ? 'white' : c('#475569', '#94A3B8'),
              boxShadow: filter === tab ? '0 4px 12px rgba(108,99,255,0.3)' : 'none'
            }}>
            {tab} {tab !== 'all' && <span style={{ opacity: 0.7, marginLeft: '4px' }}>({orders.filter(o => o.status === tab).length})</span>}
          </button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '60px 20px', background: c('white', 'rgba(255,255,255,0.03)'), borderRadius: '20px', border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.08)')}` }}>
          <ShoppingBag size={48} color="#6C63FF" style={{ margin: '0 auto 16px', opacity: 0.8 }} />
          <h3 style={{ fontSize: '18px', fontWeight: 700, color: c('#1E293B', 'white'), margin: '0 0 8px' }}>No orders</h3>
          <p style={{ color: '#64748B', fontSize: '14px', margin: 0 }}>{filter === 'all' ? 'No orders yet.' : `No ${filter} orders.`}</p>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
          {filtered.map(order => (
            <div key={order.id} style={{ padding: '20px', borderRadius: '16px', background: c('white', 'rgba(255,255,255,0.03)'), border: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.08)')}` }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', cursor: 'pointer' }} onClick={() => setExpandedOrder(expandedOrder === order.id ? null : order.id)}>
                <div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '4px' }}>
                    <p style={{ fontWeight: 800, color: c('#0F172A', 'white'), fontSize: '15px', margin: 0 }}>{order.order_number}</p>
                    <span style={{ display: 'inline-flex', alignItems: 'center', gap: '4px', padding: '2px 8px', borderRadius: '100px', fontSize: '11px', fontWeight: 700, background: ORDER_STATUSES[order.status]?.color?.includes('success') ? 'rgba(16,185,129,0.1)' : ORDER_STATUSES[order.status]?.color?.includes('warning') ? 'rgba(245,158,11,0.1)' : ORDER_STATUSES[order.status]?.color?.includes('accent') ? 'rgba(239,68,68,0.1)' : 'rgba(108,99,255,0.1)', color: ORDER_STATUSES[order.status]?.color?.includes('success') ? '#10B981' : ORDER_STATUSES[order.status]?.color?.includes('warning') ? '#F59E0B' : ORDER_STATUSES[order.status]?.color?.includes('accent') ? '#EF4444' : '#6C63FF' }}>
                      {ORDER_STATUSES[order.status]?.icon} {ORDER_STATUSES[order.status]?.label}
                    </span>
                  </div>
                  <p style={{ color: '#64748B', fontSize: '13px', margin: 0 }}>{order.profiles?.full_name} · {getTimeAgo(order.created_at)}</p>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <span style={{ fontWeight: 800, color: '#6C63FF', fontSize: '16px' }}>{formatPrice(order.total_amount)}</span>
                  {expandedOrder === order.id ? <ChevronUp size={20} color="#94A3B8" /> : <ChevronDown size={20} color="#94A3B8" />}
                </div>
              </div>

              {expandedOrder === order.id && (
                <div style={{ marginTop: '20px', paddingTop: '20px', borderTop: `1px solid ${c('#F1F5F9', 'rgba(255,255,255,0.05)')}` }}>
                  {/* Customer Info */}
                  <div style={{ background: c('#F8FAFC', 'rgba(255,255,255,0.02)'), borderRadius: '12px', padding: '16px', marginBottom: '16px' }}>
                    <p style={{ fontSize: '12px', color: '#64748B', margin: '0 0 4px', fontWeight: 600, textTransform: 'uppercase' }}>Customer Details</p>
                    <p style={{ fontSize: '15px', fontWeight: 700, color: c('#0F172A', 'white'), margin: '0 0 4px' }}>{order.profiles?.full_name}</p>
                    {order.profiles?.phone && <p style={{ fontSize: '13px', color: c('#475569', '#94A3B8'), margin: '0 0 4px' }}>📞 {order.profiles.phone}</p>}
                    {order.delivery_address && <p style={{ fontSize: '13px', color: c('#475569', '#94A3B8'), margin: '0 0 4px' }}>📍 {order.delivery_address}</p>}
                    {order.note && <p style={{ fontSize: '13px', color: c('#475569', '#94A3B8'), margin: '0', fontStyle: 'italic' }}>📝 "{order.note}"</p>}
                  </div>

                  {/* Items */}
                  <div style={{ marginBottom: '16px' }}>
                    <p style={{ fontSize: '12px', color: '#64748B', margin: '0 0 8px', fontWeight: 600, textTransform: 'uppercase' }}>Items</p>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                      {order.order_items?.map(item => (
                        <div key={item.id} style={{ display: 'flex', justifyContent: 'space-between', fontSize: '14px' }}>
                          <span style={{ color: c('#334155', '#CBD5E1') }}>{item.product_name} × <span style={{ fontWeight: 600 }}>{item.quantity}</span></span>
                          <span style={{ fontWeight: 600, color: c('#0F172A', 'white') }}>{formatPrice(item.product_price * item.quantity)}</span>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Totals & Payment */}
                  <div style={{ borderTop: `1px solid ${c('#E2E8F0', 'rgba(255,255,255,0.08)')}`, paddingTop: '12px', marginBottom: '20px' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '13px', marginBottom: '8px' }}><span style={{ color: '#64748B' }}>Payment</span><span style={{ fontWeight: 600, color: c('#334155', '#CBD5E1'), textTransform: 'uppercase' }}>{order.payment_method} · {order.payment_status}</span></div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '16px', fontWeight: 800, color: c('#0F172A', 'white') }}><span>Total Amount</span><span style={{ color: '#6C63FF' }}>{formatPrice(order.total_amount)}</span></div>
                  </div>

                  {/* Action Buttons */}
                  <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                    {order.status === 'pending' && (
                      <>
                        <button onClick={(e) => { e.stopPropagation(); updateOrderStatus(order.id, 'accepted', order.customer_id); }} style={{ flex: 1, padding: '12px', borderRadius: '12px', background: '#10B981', color: 'white', fontWeight: 700, fontSize: '14px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                          <Check size={18} /> Accept Order
                        </button>
                        <button onClick={(e) => { e.stopPropagation(); updateOrderStatus(order.id, 'rejected', order.customer_id); }} style={{ flex: 1, padding: '12px', borderRadius: '12px', background: '#EF4444', color: 'white', fontWeight: 700, fontSize: '14px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                          <X size={18} /> Reject
                        </button>
                      </>
                    )}
                    {order.status === 'accepted' && (
                      <button onClick={(e) => { e.stopPropagation(); updateOrderStatus(order.id, 'preparing', order.customer_id); }} style={{ width: '100%', padding: '12px', borderRadius: '12px', background: '#F59E0B', color: 'white', fontWeight: 700, fontSize: '14px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                        <Check size={18} /> Start Preparing
                      </button>
                    )}
                    {order.status === 'preparing' && (
                      <button onClick={(e) => { e.stopPropagation(); updateOrderStatus(order.id, 'delivered', order.customer_id); }} style={{ width: '100%', padding: '12px', borderRadius: '12px', background: '#6C63FF', color: 'white', fontWeight: 700, fontSize: '14px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                        <Truck size={18} /> Mark as Delivered
                      </button>
                    )}
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
